/**
 * Подтема PlasmaSdServiceTheme.OnDark
 */
@Composable
public fun PlasmaSdServiceTheme.OnDark(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalPlasmaSdServiceColors.current
    val overrideColors = currentColors.copyAttrs(OnDarkColorsOverride)
    val currentGradients = LocalPlasmaSdServiceGradients.current
    val overrideGradients = currentGradients.copyAttrs(OnDarkGradientsOverride)
    PlasmaSdServiceTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
